template <int NROOTS, bool kTileF32 = false, bool kMixedPrec = false>
__global__ void __launch_bounds__(128) KernelERI_psds_flat(
    const int32_t* __restrict__ task_spAB,
    const int32_t* __restrict__ task_spCD,
    int ntasks,
    const int32_t* __restrict__ sp_A,
    const int32_t* __restrict__ sp_B,
    const int32_t* __restrict__ sp_pair_start,
    const int32_t* __restrict__ sp_npair,
    const double* __restrict__ shell_cx,
    const double* __restrict__ shell_cy,
    const double* __restrict__ shell_cz,
    const double* __restrict__ pair_eta,
    const double* __restrict__ pair_Px,
    const double* __restrict__ pair_Py,
    const double* __restrict__ pair_Pz,
    const double* __restrict__ pair_cK,
    double* __restrict__ eri_out_f64,
    float*  __restrict__ eri_out_f32) {
  const int t = static_cast<int>(blockIdx.x) * static_cast<int>(blockDim.x) + static_cast<int>(threadIdx.x);
  if (t >= ntasks) return;

  const int spAB = static_cast<int>(task_spAB[t]);
  const int spCD = static_cast<int>(task_spCD[t]);
  const int A = static_cast<int>(sp_A[spAB]);
  const int B = static_cast<int>(sp_B[spAB]);
  const int C = static_cast<int>(sp_A[spCD]);
  const int D = static_cast<int>(sp_B[spCD]);

  const double Ax = shell_cx[A];
  const double Ay = shell_cy[A];
  const double Az = shell_cz[A];
  const double Bx = shell_cx[B];
  const double By = shell_cy[B];
  const double Bz = shell_cz[B];
  const double Cx = shell_cx[C];
  const double Cy = shell_cy[C];
  const double Cz = shell_cz[C];
  const double Dx = shell_cx[D];
  const double Dy = shell_cy[D];
  const double Dz = shell_cz[D];

  const double xij = Ax - Bx;
  const double yij = Ay - By;
  const double zij = Az - Bz;
  const double xkl = Cx - Dx;
  const double ykl = Cy - Dy;
  const double zkl = Cz - Dz;
  const double xij2 = xij * xij;
  const double yij2 = yij * yij;
  const double zij2 = zij * zij;
  const double xkl2 = xkl * xkl;
  const double ykl2 = ykl * ykl;
  const double zkl2 = zkl * zkl;

  const int baseAB = static_cast<int>(sp_pair_start[spAB]);
  const int baseCD = static_cast<int>(sp_pair_start[spCD]);
  const int nPairAB = static_cast<int>(sp_npair[spAB]);
  const int nPairCD = static_cast<int>(sp_npair[spCD]);

  constexpr int kFlatStride = 3;
  constexpr int kNComp = 18;
  constexpr int kNMax = 1;
  constexpr int kMMax = 2;

  // G arrays in compact layout: (nmax+1)*(mmax+1) entries per axis.
  double Gx[6];
  double Gy[6];
  double Gz[6];
  // Component type: FP32 when kMixedPrec, else FP64.
  using comp_t = typename std::conditional<kMixedPrec, float, double>::type;
  comp_t Ux[6];
  comp_t Uy[6];
  comp_t Uz[6];
  double tile[18];
  tile[0] = 0.0;
  tile[1] = 0.0;
  tile[2] = 0.0;
  tile[3] = 0.0;
  tile[4] = 0.0;
  tile[5] = 0.0;
  tile[6] = 0.0;
  tile[7] = 0.0;
  tile[8] = 0.0;
  tile[9] = 0.0;
  tile[10] = 0.0;
  tile[11] = 0.0;
  tile[12] = 0.0;
  tile[13] = 0.0;
  tile[14] = 0.0;
  tile[15] = 0.0;
  tile[16] = 0.0;
  tile[17] = 0.0;

  for (int ip = 0; ip < nPairAB; ++ip) {
    const int ki = baseAB + ip;
    const double p = pair_eta[ki];
    const double Px = pair_Px[ki];
    const double Py = pair_Py[ki];
    const double Pz = pair_Pz[ki];
    const double cKi = pair_cK[ki];
    for (int jp = 0; jp < nPairCD; ++jp) {
      const int kj = baseCD + jp;
      const double q = pair_eta[kj];
      const double Qx = pair_Px[kj];
      const double Qy = pair_Py[kj];
      const double Qz = pair_Pz[kj];
      const double dx = Px - Qx;
      const double dy = Py - Qy;
      const double dz = Pz - Qz;
      const double PQ2 = dx * dx + dy * dy + dz * dz;
      const double denom = p + q;
      const double omega = p * q / denom;
      const double T = omega * PQ2;
      const double base = kTwoPiToFiveHalves / (p * q * ::sqrt(denom)) * cKi * pair_cK[kj];
      double roots[NROOTS], weights[NROOTS];
      cueri_rys::rys_roots_weights<NROOTS>(T, roots, weights);
      for (int u = 0; u < NROOTS; ++u) {
        const double x = roots[u];
        const double w = weights[u];
        const double inv_denom = 1.0 / denom;
        const double B0 = x * 0.5 * inv_denom;
        const double B1 = (1.0 - x) * 0.5 / p + B0;
        const double B1p = (1.0 - x) * 0.5 / q + B0;

        const double Cx_ = (Px - Ax) + (q * inv_denom) * x * (Qx - Px);
        const double Cy_ = (Py - Ay) + (q * inv_denom) * x * (Qy - Py);
        const double Cz_ = (Pz - Az) + (q * inv_denom) * x * (Qz - Pz);
        const double Cpx_ = (Qx - Cx) + (p * inv_denom) * x * (Px - Qx);
        const double Cpy_ = (Qy - Cy) + (p * inv_denom) * x * (Py - Qy);
        const double Cpz_ = (Qz - Cz) + (p * inv_denom) * x * (Pz - Qz);

        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gx, Cx_, Cpx_, B0, B1, B1p);
        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gy, Cy_, Cpy_, B0, B1, B1p);
        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gz, Cz_, Cpz_, B0, B1, B1p);
        const double sc = base * w;
        Ux[0] = static_cast<comp_t>(Gx[5]);
        Ux[1] = static_cast<comp_t>(Gx[4]);
        Ux[2] = static_cast<comp_t>(Gx[3]);
        Ux[3] = static_cast<comp_t>(Gx[2]);
        Ux[4] = static_cast<comp_t>(Gx[1]);
        Ux[5] = static_cast<comp_t>(Gx[0]);
        Uy[0] = static_cast<comp_t>(Gy[0]);
        Uy[1] = static_cast<comp_t>(Gy[1]);
        Uy[2] = static_cast<comp_t>(Gy[2]);
        Uy[3] = static_cast<comp_t>(Gy[3]);
        Uy[4] = static_cast<comp_t>(Gy[4]);
        Uy[5] = static_cast<comp_t>(Gy[5]);
        Uz[0] = static_cast<comp_t>(Gz[0]);
        Uz[1] = static_cast<comp_t>(Gz[1]);
        Uz[2] = static_cast<comp_t>(Gz[2]);
        Uz[3] = static_cast<comp_t>(Gz[3]);
        Uz[4] = static_cast<comp_t>(Gz[4]);
        Uz[5] = static_cast<comp_t>(Gz[5]);
        tile[0] += sc * static_cast<double>(Ux[0] * Uy[0]) * static_cast<double>(Uz[0]);
        tile[1] += sc * static_cast<double>(Ux[1] * Uy[1]) * static_cast<double>(Uz[0]);
        tile[2] += sc * static_cast<double>(Ux[1] * Uy[0]) * static_cast<double>(Uz[1]);
        tile[3] += sc * static_cast<double>(Ux[2] * Uy[2]) * static_cast<double>(Uz[0]);
        tile[4] += sc * static_cast<double>(Ux[2] * Uy[1]) * static_cast<double>(Uz[1]);
        tile[5] += sc * static_cast<double>(Ux[2] * Uy[0]) * static_cast<double>(Uz[2]);
        tile[6] += sc * static_cast<double>(Ux[3] * Uy[3]) * static_cast<double>(Uz[0]);
        tile[7] += sc * static_cast<double>(Ux[4] * Uy[4]) * static_cast<double>(Uz[0]);
        tile[8] += sc * static_cast<double>(Ux[4] * Uy[3]) * static_cast<double>(Uz[1]);
        tile[9] += sc * static_cast<double>(Ux[5] * Uy[5]) * static_cast<double>(Uz[0]);
        tile[10] += sc * static_cast<double>(Ux[5] * Uy[4]) * static_cast<double>(Uz[1]);
        tile[11] += sc * static_cast<double>(Ux[5] * Uy[3]) * static_cast<double>(Uz[2]);
        tile[12] += sc * static_cast<double>(Ux[3] * Uy[0]) * static_cast<double>(Uz[3]);
        tile[13] += sc * static_cast<double>(Ux[4] * Uy[1]) * static_cast<double>(Uz[3]);
        tile[14] += sc * static_cast<double>(Ux[4] * Uy[0]) * static_cast<double>(Uz[4]);
        tile[15] += sc * static_cast<double>(Ux[5] * Uy[2]) * static_cast<double>(Uz[3]);
        tile[16] += sc * static_cast<double>(Ux[5] * Uy[1]) * static_cast<double>(Uz[4]);
        tile[17] += sc * static_cast<double>(Ux[5] * Uy[0]) * static_cast<double>(Uz[5]);
      }
    }
  }

  // Write output tile: FP32 or FP64 depending on kTileF32.
  if constexpr (kTileF32) {
    float* out = eri_out_f32 + static_cast<int64_t>(t) * static_cast<int64_t>(18);
    out[0] = __double2float_rn(tile[0]);
    out[1] = __double2float_rn(tile[1]);
    out[2] = __double2float_rn(tile[2]);
    out[3] = __double2float_rn(tile[3]);
    out[4] = __double2float_rn(tile[4]);
    out[5] = __double2float_rn(tile[5]);
    out[6] = __double2float_rn(tile[6]);
    out[7] = __double2float_rn(tile[7]);
    out[8] = __double2float_rn(tile[8]);
    out[9] = __double2float_rn(tile[9]);
    out[10] = __double2float_rn(tile[10]);
    out[11] = __double2float_rn(tile[11]);
    out[12] = __double2float_rn(tile[12]);
    out[13] = __double2float_rn(tile[13]);
    out[14] = __double2float_rn(tile[14]);
    out[15] = __double2float_rn(tile[15]);
    out[16] = __double2float_rn(tile[16]);
    out[17] = __double2float_rn(tile[17]);
  } else {
    double* out = eri_out_f64 + static_cast<int64_t>(t) * static_cast<int64_t>(18);
    out[0] = tile[0];
    out[1] = tile[1];
    out[2] = tile[2];
    out[3] = tile[3];
    out[4] = tile[4];
    out[5] = tile[5];
    out[6] = tile[6];
    out[7] = tile[7];
    out[8] = tile[8];
    out[9] = tile[9];
    out[10] = tile[10];
    out[11] = tile[11];
    out[12] = tile[12];
    out[13] = tile[13];
    out[14] = tile[14];
    out[15] = tile[15];
    out[16] = tile[16];
    out[17] = tile[17];
  }
}

template <int NROOTS>
__global__ void KernelERI_psds_warp_true(
    const int32_t* __restrict__ task_spAB,
    const int32_t* __restrict__ task_spCD,
    int ntasks,
    const int32_t* __restrict__ sp_A,
    const int32_t* __restrict__ sp_B,
    const int32_t* __restrict__ sp_pair_start,
    const int32_t* __restrict__ sp_npair,
    const double* __restrict__ shell_cx,
    const double* __restrict__ shell_cy,
    const double* __restrict__ shell_cz,
    const double* __restrict__ pair_eta,
    const double* __restrict__ pair_Px,
    const double* __restrict__ pair_Py,
    const double* __restrict__ pair_Pz,
    const double* __restrict__ pair_cK,
    double* __restrict__ eri_out) {
  const int lane = static_cast<int>(threadIdx.x) & 31;
  const int warp_id = static_cast<int>(threadIdx.x) >> 5;
  const int warps_per_block = static_cast<int>(blockDim.x) >> 5;
  const int t = static_cast<int>(blockIdx.x) * warps_per_block + warp_id;
  if (t >= ntasks) return;

  const int spAB = static_cast<int>(task_spAB[t]);
  const int spCD = static_cast<int>(task_spCD[t]);
  const int iA = static_cast<int>(sp_A[spAB]);
  const int iB = static_cast<int>(sp_B[spAB]);
  const int iC = static_cast<int>(sp_A[spCD]);
  const int iD = static_cast<int>(sp_B[spCD]);

  const double Ax = shell_cx[iA];
  const double Ay = shell_cy[iA];
  const double Az = shell_cz[iA];
  const double Bx = shell_cx[iB];
  const double By = shell_cy[iB];
  const double Bz = shell_cz[iB];
  const double Cx = shell_cx[iC];
  const double Cy = shell_cy[iC];
  const double Cz = shell_cz[iC];
  const double Dx = shell_cx[iD];
  const double Dy = shell_cy[iD];
  const double Dz = shell_cz[iD];

  const double xij = Ax - Bx;
  const double yij = Ay - By;
  const double zij = Az - Bz;
  const double xkl = Cx - Dx;
  const double ykl = Cy - Dy;
  const double zkl = Cz - Dz;
  const double xij2 = xij * xij;
  const double yij2 = yij * yij;
  const double zij2 = zij * zij;
  const double xkl2 = xkl * xkl;
  const double ykl2 = ykl * ykl;
  const double zkl2 = zkl * zkl;

  const int baseAB = static_cast<int>(sp_pair_start[spAB]);
  const int baseCD = static_cast<int>(sp_pair_start[spCD]);
  const int nPairAB = static_cast<int>(sp_npair[spAB]);
  const int nPairCD = static_cast<int>(sp_npair[spCD]);
  const int totalPairs = nPairAB * nPairCD;

  constexpr int kStride = 7;
  constexpr int kNComp = 18;
  constexpr int kNMax = 1;
  constexpr int kMMax = 2;
  constexpr int kGSize = 49;

  // Per-lane accumulators in registers.
  double acc[kNComp];
  #pragma unroll
  for (int i = 0; i < kNComp; ++i) acc[i] = 0.0;

  // Lane-parallel primitive pair loop.
  for (int pair = lane; pair < totalPairs; pair += 32) {
    const int ip = pair / nPairCD;
    const int jp = pair - ip * nPairCD;
    const int ki = baseAB + ip;
    const int kj = baseCD + jp;

    const double p = pair_eta[ki];
    const double q = pair_eta[kj];
    const double Px = pair_Px[ki];
    const double Py = pair_Py[ki];
    const double Pz = pair_Pz[ki];
    const double Qx = pair_Px[kj];
    const double Qy = pair_Py[kj];
    const double Qz = pair_Pz[kj];

    const double dxPQ = Px - Qx;
    const double dyPQ = Py - Qy;
    const double dzPQ = Pz - Qz;
    const double PQ2 = dxPQ * dxPQ + dyPQ * dyPQ + dzPQ * dzPQ;

    const double denom = p + q;
    const double omega = p * q / denom;
    const double T = omega * PQ2;
    const double base = kTwoPiToFiveHalves / (p * q * ::sqrt(denom)) * pair_cK[ki] * pair_cK[kj];

    // Rys roots/weights in registers — each lane computes independently.
    double roots[NROOTS];
    double weights[NROOTS];
    cueri_rys::rys_roots_weights<NROOTS>(T, roots, weights);

    for (int u = 0; u < NROOTS; ++u) {
      const double x = roots[u];
      const double w = weights[u];
      const double inv_denom = 1.0 / denom;
      const double B0 = x * 0.5 * inv_denom;
      const double B1 = (1.0 - x) * 0.5 / p + B0;
      const double B1p = (1.0 - x) * 0.5 / q + B0;

      const double Cx_ = (Px - Ax) + (q * inv_denom) * x * (Qx - Px);
      const double Cy_ = (Py - Ay) + (q * inv_denom) * x * (Qy - Py);
      const double Cz_ = (Pz - Az) + (q * inv_denom) * x * (Qz - Pz);
      const double Cpx_ = (Qx - Cx) + (p * inv_denom) * x * (Px - Qx);
      const double Cpy_ = (Qy - Cy) + (p * inv_denom) * x * (Py - Qy);
      const double Cpz_ = (Qz - Cz) + (p * inv_denom) * x * (Pz - Qz);

      // G arrays in local memory (registers/L1).
      double Gx[kGSize];
      double Gy[kGSize];
      double Gz[kGSize];
      compute_G_stride_fixed<kStride, kNMax, kMMax>(Gx, Cx_, Cpx_, B0, B1, B1p);
      compute_G_stride_fixed<kStride, kNMax, kMMax>(Gy, Cy_, Cpy_, B0, B1, B1p);
      compute_G_stride_fixed<kStride, kNMax, kMMax>(Gz, Cz_, Cpz_, B0, B1, B1p);

      const double scale = base * w;

      // Accumulate all components.
            acc[0] += scale * (Gx[9]) * (Gy[0]) * (Gz[0]);
            acc[1] += scale * (Gx[8]) * (Gy[1]) * (Gz[0]);
            acc[2] += scale * (Gx[8]) * (Gy[0]) * (Gz[1]);
            acc[3] += scale * (Gx[7]) * (Gy[2]) * (Gz[0]);
            acc[4] += scale * (Gx[7]) * (Gy[1]) * (Gz[1]);
            acc[5] += scale * (Gx[7]) * (Gy[0]) * (Gz[2]);
            acc[6] += scale * (Gx[2]) * (Gy[7]) * (Gz[0]);
            acc[7] += scale * (Gx[1]) * (Gy[8]) * (Gz[0]);
            acc[8] += scale * (Gx[1]) * (Gy[7]) * (Gz[1]);
            acc[9] += scale * (Gx[0]) * (Gy[9]) * (Gz[0]);
            acc[10] += scale * (Gx[0]) * (Gy[8]) * (Gz[1]);
            acc[11] += scale * (Gx[0]) * (Gy[7]) * (Gz[2]);
            acc[12] += scale * (Gx[2]) * (Gy[0]) * (Gz[7]);
            acc[13] += scale * (Gx[1]) * (Gy[1]) * (Gz[7]);
            acc[14] += scale * (Gx[1]) * (Gy[0]) * (Gz[8]);
            acc[15] += scale * (Gx[0]) * (Gy[2]) * (Gz[7]);
            acc[16] += scale * (Gx[0]) * (Gy[1]) * (Gz[8]);
            acc[17] += scale * (Gx[0]) * (Gy[0]) * (Gz[9]);
    }  // for u (Rys roots)
  }  // for pair

  // Warp reduction: sum across lanes.
  #pragma unroll
  for (int i = 0; i < kNComp; ++i) {
    #pragma unroll
    for (int offset = 16; offset > 0; offset >>= 1) {
      acc[i] += __shfl_down_sync(0xFFFFFFFF, acc[i], offset);
    }
  }

  // Lane 0 writes output.
  if (lane == 0) {
    double* out = eri_out + static_cast<int64_t>(t) * static_cast<int64_t>(kNComp);
    #pragma unroll
    for (int i = 0; i < kNComp; ++i) out[i] = acc[i];
  }
}

template <int NROOTS, bool kMixedPrec = false>
__global__ void __launch_bounds__(64) KernelFusedFock_psds_fixed(
    const int32_t* task_spAB,
    const int32_t* task_spCD,
    int ntasks,
    const int32_t* sp_A,
    const int32_t* sp_B,
    const int32_t* sp_pair_start,
    const int32_t* sp_npair,
    const double* shell_cx,
    const double* shell_cy,
    const double* shell_cz,
    const double* pair_eta,
    const double* pair_Px,
    const double* pair_Py,
    const double* pair_Pz,
    const double* pair_cK,
    const int32_t* shell_ao_start,
    int nao,
    const double* D_mat,
    double* F_mat,
    int n_bufs) {
  const int lane = static_cast<int>(threadIdx.x) & 31;
  const int warp_id = static_cast<int>(threadIdx.x) >> 5;
  const int warps_per_block = static_cast<int>(blockDim.x) >> 5;
  const int t = static_cast<int>(blockIdx.x) * warps_per_block + warp_id;
  if (t >= ntasks) return;

  constexpr int kStride = 7;
  constexpr int kNComp = 18;
  constexpr int kNMax = 1;
  constexpr int kMMax = 2;
  constexpr int kGSize = kStride * kStride;
  constexpr int kWarpDoubles = 3 * kGSize + 2 * NROOTS + 11 + kNComp;

  extern __shared__ char sh_raw[];
  double* sh_warp = reinterpret_cast<double*>(sh_raw) + static_cast<int64_t>(warp_id) * kWarpDoubles;
  double* Gx = sh_warp;
  double* Gy = sh_warp + kGSize;
  double* Gz = sh_warp + 2 * kGSize;
  double* sh_roots = sh_warp + 3 * kGSize;
  double* sh_weights = sh_roots + NROOTS;
  double* sh_sc = sh_weights + NROOTS;
  double* tile = sh_sc + 11;

  const int spAB = static_cast<int>(task_spAB[t]);
  const int spCD = static_cast<int>(task_spCD[t]);
  const int A = static_cast<int>(sp_A[spAB]);
  const int B = static_cast<int>(sp_B[spAB]);
  const int C = static_cast<int>(sp_A[spCD]);
  const int D = static_cast<int>(sp_B[spCD]);

  const double Ax = shell_cx[A];
  const double Ay = shell_cy[A];
  const double Az = shell_cz[A];
  const double Bx = shell_cx[B];
  const double By = shell_cy[B];
  const double Bz = shell_cz[B];
  const double Cx = shell_cx[C];
  const double Cy = shell_cy[C];
  const double Cz = shell_cz[C];
  const double Dx = shell_cx[D];
  const double Dy = shell_cy[D];
  const double Dz = shell_cz[D];

  const double xij = Ax - Bx;
  const double yij = Ay - By;
  const double zij = Az - Bz;
  const double xkl = Cx - Dx;
  const double ykl = Cy - Dy;
  const double zkl = Cz - Dz;
  const double xij2 = xij * xij;
  const double yij2 = yij * yij;
  const double zij2 = zij * zij;
  const double xkl2 = xkl * xkl;
  const double ykl2 = ykl * ykl;
  const double zkl2 = zkl * zkl;

  const int baseAB = static_cast<int>(sp_pair_start[spAB]);
  const int baseCD = static_cast<int>(sp_pair_start[spCD]);
  const int nPairAB = static_cast<int>(sp_npair[spAB]);
  const int nPairCD = static_cast<int>(sp_npair[spCD]);

  using comp_t = typename std::conditional<kMixedPrec, float, double>::type;

  for (int ebase = 0; ebase < kNComp; ebase += 32) {
    const int e = ebase + lane;
    const bool active = (e < kNComp);
    double val = 0.0;
    for (int ip = 0; ip < nPairAB; ++ip) {
      const int ki = baseAB + ip;
      for (int jp = 0; jp < nPairCD; ++jp) {
        const int kj = baseCD + jp;
        if (lane == 0) {
          sh_sc[1] = pair_eta[ki];
          sh_sc[2] = pair_eta[kj];
          sh_sc[3] = pair_Px[ki];
          sh_sc[4] = pair_Py[ki];
          sh_sc[5] = pair_Pz[ki];
          sh_sc[6] = pair_Px[kj];
          sh_sc[7] = pair_Py[kj];
          sh_sc[8] = pair_Pz[kj];
          const double dx = sh_sc[3] - sh_sc[6];
          const double dy = sh_sc[4] - sh_sc[7];
          const double dz = sh_sc[5] - sh_sc[8];
          const double PQ2 = dx * dx + dy * dy + dz * dz;
          sh_sc[9] = sh_sc[1] + sh_sc[2];
          const double omega = sh_sc[1] * sh_sc[2] / sh_sc[9];
          const double T = omega * PQ2;
          sh_sc[10] = kTwoPiToFiveHalves / (sh_sc[1] * sh_sc[2] * ::sqrt(sh_sc[9])) * pair_cK[ki] * pair_cK[kj];
          cueri_rys::rys_roots_weights<NROOTS>(T, sh_roots, sh_weights);
        }
        __syncwarp();
        for (int u = 0; u < NROOTS; ++u) {
          if (lane == 0) {
            const double x = sh_roots[u];
            const double w = sh_weights[u];
            const double inv_denom = 1.0 / sh_sc[9];
            const double B0 = x * 0.5 * inv_denom;
            const double B1 = (1.0 - x) * 0.5 / sh_sc[1] + B0;
            const double B1p = (1.0 - x) * 0.5 / sh_sc[2] + B0;

            const double Cx_ = (sh_sc[3] - Ax) + (sh_sc[2] * inv_denom) * x * (sh_sc[6] - sh_sc[3]);
            const double Cy_ = (sh_sc[4] - Ay) + (sh_sc[2] * inv_denom) * x * (sh_sc[7] - sh_sc[4]);
            const double Cz_ = (sh_sc[5] - Az) + (sh_sc[2] * inv_denom) * x * (sh_sc[8] - sh_sc[5]);
            const double Cpx_ = (sh_sc[6] - Cx) + (sh_sc[1] * inv_denom) * x * (sh_sc[3] - sh_sc[6]);
            const double Cpy_ = (sh_sc[7] - Cy) + (sh_sc[1] * inv_denom) * x * (sh_sc[4] - sh_sc[7]);
            const double Cpz_ = (sh_sc[8] - Cz) + (sh_sc[1] * inv_denom) * x * (sh_sc[5] - sh_sc[8]);

            compute_G_stride_fixed<kStride, kNMax, kMMax>(Gx, Cx_, Cpx_, B0, B1, B1p);
            compute_G_stride_fixed<kStride, kNMax, kMMax>(Gy, Cy_, Cpy_, B0, B1, B1p);
            compute_G_stride_fixed<kStride, kNMax, kMMax>(Gz, Cz_, Cpz_, B0, B1, B1p);
            sh_sc[0] = sh_sc[10] * w;
          }
          __syncwarp();
          if (active) {
            const comp_t Ix = static_cast<comp_t>(eval_psds_x(e, Gx, xij, xij2, xkl, xkl2));
            const comp_t Iy = static_cast<comp_t>(eval_psds_y(e, Gy, yij, yij2, ykl, ykl2));
            const comp_t Iz = static_cast<comp_t>(eval_psds_z(e, Gz, zij, zij2, zkl, zkl2));
            val += sh_sc[0] * static_cast<double>(Ix * Iy) * static_cast<double>(Iz);
          }
          __syncwarp();
        }
      }
    }
    if (active) tile[e] = val;
  }

  __syncwarp();
  {
    constexpr int nA = 3, nB = 1, nC = 6, nD = 1;
    constexpr int nAB = 3;
    constexpr int nCD = 6;
    const int a0 = static_cast<int>(shell_ao_start[A]);
    const int b0 = static_cast<int>(shell_ao_start[B]);
    const int c0 = static_cast<int>(shell_ao_start[C]);
    const int d0 = static_cast<int>(shell_ao_start[D]);
    const bool ab_neq = (A != B);
    const bool cd_neq = (C != D);
    const bool bk_swap = (spAB != spCD);
    const double f_ab = ab_neq ? 2.0 : 1.0;
    const double f_cd = cd_neq ? 2.0 : 1.0;
    const int64_t N = static_cast<int64_t>(nao);
    const int buf_id = static_cast<int>(blockIdx.x) % n_bufs;
    cueri_contract_fock_warp_single(
        tile, D_mat, F_mat, lane,
        nAB, nCD, nA, nB, nC, nD,
        a0, b0, c0, d0,
        ab_neq, cd_neq, bk_swap, f_ab, f_cd, N, n_bufs, buf_id);
  }
}

template <int NROOTS, bool kMixedPrec = false>
__global__ void __launch_bounds__(64) KernelFusedJK_psds_fixed(
    const int32_t* task_spAB,
    const int32_t* task_spCD,
    int ntasks,
    const int32_t* sp_A,
    const int32_t* sp_B,
    const int32_t* sp_pair_start,
    const int32_t* sp_npair,
    const double* shell_cx,
    const double* shell_cy,
    const double* shell_cz,
    const double* pair_eta,
    const double* pair_Px,
    const double* pair_Py,
    const double* pair_Pz,
    const double* pair_cK,
    const int32_t* shell_ao_start,
    int nao,
    const double* D_mat,
    double* J_mat,
    double* K_mat,
    int n_bufs) {
  const int lane = static_cast<int>(threadIdx.x) & 31;
  const int warp_id = static_cast<int>(threadIdx.x) >> 5;
  const int warps_per_block = static_cast<int>(blockDim.x) >> 5;
  const int t = static_cast<int>(blockIdx.x) * warps_per_block + warp_id;
  if (t >= ntasks) return;

  constexpr int kStride = 7;
  constexpr int kNComp = 18;
  constexpr int kNMax = 1;
  constexpr int kMMax = 2;
  constexpr int kGSize = kStride * kStride;
  constexpr int kWarpDoubles = 3 * kGSize + 2 * NROOTS + 11 + kNComp;

  extern __shared__ char sh_raw[];
  double* sh_warp = reinterpret_cast<double*>(sh_raw) + static_cast<int64_t>(warp_id) * kWarpDoubles;
  double* Gx = sh_warp;
  double* Gy = sh_warp + kGSize;
  double* Gz = sh_warp + 2 * kGSize;
  double* sh_roots = sh_warp + 3 * kGSize;
  double* sh_weights = sh_roots + NROOTS;
  double* sh_sc = sh_weights + NROOTS;
  double* tile = sh_sc + 11;

  const int spAB = static_cast<int>(task_spAB[t]);
  const int spCD = static_cast<int>(task_spCD[t]);
  const int A = static_cast<int>(sp_A[spAB]);
  const int B = static_cast<int>(sp_B[spAB]);
  const int C = static_cast<int>(sp_A[spCD]);
  const int D = static_cast<int>(sp_B[spCD]);

  const double Ax = shell_cx[A];
  const double Ay = shell_cy[A];
  const double Az = shell_cz[A];
  const double Bx = shell_cx[B];
  const double By = shell_cy[B];
  const double Bz = shell_cz[B];
  const double Cx = shell_cx[C];
  const double Cy = shell_cy[C];
  const double Cz = shell_cz[C];
  const double Dx = shell_cx[D];
  const double Dy = shell_cy[D];
  const double Dz = shell_cz[D];

  const double xij = Ax - Bx;
  const double yij = Ay - By;
  const double zij = Az - Bz;
  const double xkl = Cx - Dx;
  const double ykl = Cy - Dy;
  const double zkl = Cz - Dz;
  const double xij2 = xij * xij;
  const double yij2 = yij * yij;
  const double zij2 = zij * zij;
  const double xkl2 = xkl * xkl;
  const double ykl2 = ykl * ykl;
  const double zkl2 = zkl * zkl;

  const int baseAB = static_cast<int>(sp_pair_start[spAB]);
  const int baseCD = static_cast<int>(sp_pair_start[spCD]);
  const int nPairAB = static_cast<int>(sp_npair[spAB]);
  const int nPairCD = static_cast<int>(sp_npair[spCD]);

  using comp_t = typename std::conditional<kMixedPrec, float, double>::type;

  for (int ebase = 0; ebase < kNComp; ebase += 32) {
    const int e = ebase + lane;
    const bool active = (e < kNComp);
    double val = 0.0;
    for (int ip = 0; ip < nPairAB; ++ip) {
      const int ki = baseAB + ip;
      for (int jp = 0; jp < nPairCD; ++jp) {
        const int kj = baseCD + jp;
        if (lane == 0) {
          sh_sc[1] = pair_eta[ki];
          sh_sc[2] = pair_eta[kj];
          sh_sc[3] = pair_Px[ki];
          sh_sc[4] = pair_Py[ki];
          sh_sc[5] = pair_Pz[ki];
          sh_sc[6] = pair_Px[kj];
          sh_sc[7] = pair_Py[kj];
          sh_sc[8] = pair_Pz[kj];
          const double dx = sh_sc[3] - sh_sc[6];
          const double dy = sh_sc[4] - sh_sc[7];
          const double dz = sh_sc[5] - sh_sc[8];
          const double PQ2 = dx * dx + dy * dy + dz * dz;
          sh_sc[9] = sh_sc[1] + sh_sc[2];
          const double omega = sh_sc[1] * sh_sc[2] / sh_sc[9];
          const double T = omega * PQ2;
          sh_sc[10] = kTwoPiToFiveHalves / (sh_sc[1] * sh_sc[2] * ::sqrt(sh_sc[9])) * pair_cK[ki] * pair_cK[kj];
          cueri_rys::rys_roots_weights<NROOTS>(T, sh_roots, sh_weights);
        }
        __syncwarp();
        for (int u = 0; u < NROOTS; ++u) {
          if (lane == 0) {
            const double x = sh_roots[u];
            const double w = sh_weights[u];
            const double inv_denom = 1.0 / sh_sc[9];
            const double B0 = x * 0.5 * inv_denom;
            const double B1 = (1.0 - x) * 0.5 / sh_sc[1] + B0;
            const double B1p = (1.0 - x) * 0.5 / sh_sc[2] + B0;

            const double Cx_ = (sh_sc[3] - Ax) + (sh_sc[2] * inv_denom) * x * (sh_sc[6] - sh_sc[3]);
            const double Cy_ = (sh_sc[4] - Ay) + (sh_sc[2] * inv_denom) * x * (sh_sc[7] - sh_sc[4]);
            const double Cz_ = (sh_sc[5] - Az) + (sh_sc[2] * inv_denom) * x * (sh_sc[8] - sh_sc[5]);
            const double Cpx_ = (sh_sc[6] - Cx) + (sh_sc[1] * inv_denom) * x * (sh_sc[3] - sh_sc[6]);
            const double Cpy_ = (sh_sc[7] - Cy) + (sh_sc[1] * inv_denom) * x * (sh_sc[4] - sh_sc[7]);
            const double Cpz_ = (sh_sc[8] - Cz) + (sh_sc[1] * inv_denom) * x * (sh_sc[5] - sh_sc[8]);

            compute_G_stride_fixed<kStride, kNMax, kMMax>(Gx, Cx_, Cpx_, B0, B1, B1p);
            compute_G_stride_fixed<kStride, kNMax, kMMax>(Gy, Cy_, Cpy_, B0, B1, B1p);
            compute_G_stride_fixed<kStride, kNMax, kMMax>(Gz, Cz_, Cpz_, B0, B1, B1p);
            sh_sc[0] = sh_sc[10] * w;
          }
          __syncwarp();
          if (active) {
            const comp_t Ix = static_cast<comp_t>(eval_psds_x(e, Gx, xij, xij2, xkl, xkl2));
            const comp_t Iy = static_cast<comp_t>(eval_psds_y(e, Gy, yij, yij2, ykl, ykl2));
            const comp_t Iz = static_cast<comp_t>(eval_psds_z(e, Gz, zij, zij2, zkl, zkl2));
            val += sh_sc[0] * static_cast<double>(Ix * Iy) * static_cast<double>(Iz);
          }
          __syncwarp();
        }
      }
    }
    if (active) tile[e] = val;
  }

  __syncwarp();
  {
    constexpr int nA = 3, nB = 1, nC = 6, nD = 1;
    constexpr int nAB = 3;
    constexpr int nCD = 6;
    const int a0 = static_cast<int>(shell_ao_start[A]);
    const int b0 = static_cast<int>(shell_ao_start[B]);
    const int c0 = static_cast<int>(shell_ao_start[C]);
    const int d0 = static_cast<int>(shell_ao_start[D]);
    const bool ab_neq = (A != B);
    const bool cd_neq = (C != D);
    const bool bk_swap = (spAB != spCD);
    const double f_ab = ab_neq ? 2.0 : 1.0;
    const double f_cd = cd_neq ? 2.0 : 1.0;
    const int64_t N = static_cast<int64_t>(nao);
    const int buf_id = static_cast<int>(blockIdx.x) % n_bufs;
    cueri_contract_jk_warp_single(
        tile, D_mat, J_mat, K_mat, lane,
        nAB, nCD, nA, nB, nC, nD,
        a0, b0, c0, d0,
        ab_neq, cd_neq, bk_swap, f_ab, f_cd, N, n_bufs, buf_id);
  }
}

template <int NROOTS, bool kTileF32 = false, bool kMixedPrec = false>
__global__ void __launch_bounds__(128) KernelERI_ppds_flat(
    const int32_t* __restrict__ task_spAB,
    const int32_t* __restrict__ task_spCD,
    int ntasks,
    const int32_t* __restrict__ sp_A,
    const int32_t* __restrict__ sp_B,
    const int32_t* __restrict__ sp_pair_start,
    const int32_t* __restrict__ sp_npair,
    const double* __restrict__ shell_cx,
    const double* __restrict__ shell_cy,
    const double* __restrict__ shell_cz,
    const double* __restrict__ pair_eta,
    const double* __restrict__ pair_Px,
    const double* __restrict__ pair_Py,
    const double* __restrict__ pair_Pz,
    const double* __restrict__ pair_cK,
    double* __restrict__ eri_out_f64,
    float*  __restrict__ eri_out_f32) {
  const int t = static_cast<int>(blockIdx.x) * static_cast<int>(blockDim.x) + static_cast<int>(threadIdx.x);
  if (t >= ntasks) return;

  const int spAB = static_cast<int>(task_spAB[t]);
  const int spCD = static_cast<int>(task_spCD[t]);
  const int A = static_cast<int>(sp_A[spAB]);
  const int B = static_cast<int>(sp_B[spAB]);
  const int C = static_cast<int>(sp_A[spCD]);
  const int D = static_cast<int>(sp_B[spCD]);

  const double Ax = shell_cx[A];
  const double Ay = shell_cy[A];
  const double Az = shell_cz[A];
  const double Bx = shell_cx[B];
  const double By = shell_cy[B];
  const double Bz = shell_cz[B];
  const double Cx = shell_cx[C];
  const double Cy = shell_cy[C];
  const double Cz = shell_cz[C];
  const double Dx = shell_cx[D];
  const double Dy = shell_cy[D];
  const double Dz = shell_cz[D];

  const double xij = Ax - Bx;
  const double yij = Ay - By;
  const double zij = Az - Bz;
  const double xkl = Cx - Dx;
  const double ykl = Cy - Dy;
  const double zkl = Cz - Dz;
  const double xij2 = xij * xij;
  const double yij2 = yij * yij;
  const double zij2 = zij * zij;
  const double xkl2 = xkl * xkl;
  const double ykl2 = ykl * ykl;
  const double zkl2 = zkl * zkl;

  const int baseAB = static_cast<int>(sp_pair_start[spAB]);
  const int baseCD = static_cast<int>(sp_pair_start[spCD]);
  const int nPairAB = static_cast<int>(sp_npair[spAB]);
  const int nPairCD = static_cast<int>(sp_npair[spCD]);

  constexpr int kFlatStride = 3;
  constexpr int kNComp = 54;
  constexpr int kNMax = 2;
  constexpr int kMMax = 2;

  // G arrays in compact layout: (nmax+1)*(mmax+1) entries per axis.
  double Gx[9];
  double Gy[9];
  double Gz[9];
  // Component type: FP32 when kMixedPrec, else FP64.
  using comp_t = typename std::conditional<kMixedPrec, float, double>::type;
  comp_t Ux[12];
  comp_t Uy[12];
  comp_t Uz[12];
  double tile[54];
  tile[0] = 0.0;
  tile[1] = 0.0;
  tile[2] = 0.0;
  tile[3] = 0.0;
  tile[4] = 0.0;
  tile[5] = 0.0;
  tile[6] = 0.0;
  tile[7] = 0.0;
  tile[8] = 0.0;
  tile[9] = 0.0;
  tile[10] = 0.0;
  tile[11] = 0.0;
  tile[12] = 0.0;
  tile[13] = 0.0;
  tile[14] = 0.0;
  tile[15] = 0.0;
  tile[16] = 0.0;
  tile[17] = 0.0;
  tile[18] = 0.0;
  tile[19] = 0.0;
  tile[20] = 0.0;
  tile[21] = 0.0;
  tile[22] = 0.0;
  tile[23] = 0.0;
  tile[24] = 0.0;
  tile[25] = 0.0;
  tile[26] = 0.0;
  tile[27] = 0.0;
  tile[28] = 0.0;
  tile[29] = 0.0;
  tile[30] = 0.0;
  tile[31] = 0.0;
  tile[32] = 0.0;
  tile[33] = 0.0;
  tile[34] = 0.0;
  tile[35] = 0.0;
  tile[36] = 0.0;
  tile[37] = 0.0;
  tile[38] = 0.0;
  tile[39] = 0.0;
  tile[40] = 0.0;
  tile[41] = 0.0;
  tile[42] = 0.0;
  tile[43] = 0.0;
  tile[44] = 0.0;
  tile[45] = 0.0;
  tile[46] = 0.0;
  tile[47] = 0.0;
  tile[48] = 0.0;
  tile[49] = 0.0;
  tile[50] = 0.0;
  tile[51] = 0.0;
  tile[52] = 0.0;
  tile[53] = 0.0;

  for (int ip = 0; ip < nPairAB; ++ip) {
    const int ki = baseAB + ip;
    const double p = pair_eta[ki];
    const double Px = pair_Px[ki];
    const double Py = pair_Py[ki];
    const double Pz = pair_Pz[ki];
    const double cKi = pair_cK[ki];
    for (int jp = 0; jp < nPairCD; ++jp) {
      const int kj = baseCD + jp;
      const double q = pair_eta[kj];
      const double Qx = pair_Px[kj];
      const double Qy = pair_Py[kj];
      const double Qz = pair_Pz[kj];
      const double dx = Px - Qx;
      const double dy = Py - Qy;
      const double dz = Pz - Qz;
      const double PQ2 = dx * dx + dy * dy + dz * dz;
      const double denom = p + q;
      const double omega = p * q / denom;
      const double T = omega * PQ2;
      const double base = kTwoPiToFiveHalves / (p * q * ::sqrt(denom)) * cKi * pair_cK[kj];
      double roots[NROOTS], weights[NROOTS];
      cueri_rys::rys_roots_weights<NROOTS>(T, roots, weights);
      for (int u = 0; u < NROOTS; ++u) {
        const double x = roots[u];
        const double w = weights[u];
        const double inv_denom = 1.0 / denom;
        const double B0 = x * 0.5 * inv_denom;
        const double B1 = (1.0 - x) * 0.5 / p + B0;
        const double B1p = (1.0 - x) * 0.5 / q + B0;

        const double Cx_ = (Px - Ax) + (q * inv_denom) * x * (Qx - Px);
        const double Cy_ = (Py - Ay) + (q * inv_denom) * x * (Qy - Py);
        const double Cz_ = (Pz - Az) + (q * inv_denom) * x * (Qz - Pz);
        const double Cpx_ = (Qx - Cx) + (p * inv_denom) * x * (Px - Qx);
        const double Cpy_ = (Qy - Cy) + (p * inv_denom) * x * (Py - Qy);
        const double Cpz_ = (Qz - Cz) + (p * inv_denom) * x * (Pz - Qz);

        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gx, Cx_, Cpx_, B0, B1, B1p);
        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gy, Cy_, Cpy_, B0, B1, B1p);
        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gz, Cz_, Cpz_, B0, B1, B1p);
        const double sc = base * w;
        Ux[0] = static_cast<comp_t>(Gx[5] * xij + Gx[8]);
        Ux[1] = static_cast<comp_t>(Gx[4] * xij + Gx[7]);
        Ux[2] = static_cast<comp_t>(Gx[3] * xij + Gx[6]);
        Ux[3] = static_cast<comp_t>(Gx[5]);
        Ux[4] = static_cast<comp_t>(Gx[4]);
        Ux[5] = static_cast<comp_t>(Gx[3]);
        Ux[6] = static_cast<comp_t>(Gx[2] * xij + Gx[5]);
        Ux[7] = static_cast<comp_t>(Gx[1] * xij + Gx[4]);
        Ux[8] = static_cast<comp_t>(Gx[0] * xij + Gx[3]);
        Ux[9] = static_cast<comp_t>(Gx[2]);
        Ux[10] = static_cast<comp_t>(Gx[1]);
        Ux[11] = static_cast<comp_t>(Gx[0]);
        Uy[0] = static_cast<comp_t>(Gy[0]);
        Uy[1] = static_cast<comp_t>(Gy[1]);
        Uy[2] = static_cast<comp_t>(Gy[2]);
        Uy[3] = static_cast<comp_t>(Gy[0] * yij + Gy[3]);
        Uy[4] = static_cast<comp_t>(Gy[1] * yij + Gy[4]);
        Uy[5] = static_cast<comp_t>(Gy[2] * yij + Gy[5]);
        Uy[6] = static_cast<comp_t>(Gy[3]);
        Uy[7] = static_cast<comp_t>(Gy[4]);
        Uy[8] = static_cast<comp_t>(Gy[5]);
        Uy[9] = static_cast<comp_t>(Gy[3] * yij + Gy[6]);
        Uy[10] = static_cast<comp_t>(Gy[4] * yij + Gy[7]);
        Uy[11] = static_cast<comp_t>(Gy[5] * yij + Gy[8]);
        Uz[0] = static_cast<comp_t>(Gz[0]);
        Uz[1] = static_cast<comp_t>(Gz[1]);
        Uz[2] = static_cast<comp_t>(Gz[2]);
        Uz[3] = static_cast<comp_t>(Gz[0] * zij + Gz[3]);
        Uz[4] = static_cast<comp_t>(Gz[1] * zij + Gz[4]);
        Uz[5] = static_cast<comp_t>(Gz[2] * zij + Gz[5]);
        Uz[6] = static_cast<comp_t>(Gz[3]);
        Uz[7] = static_cast<comp_t>(Gz[4]);
        Uz[8] = static_cast<comp_t>(Gz[5]);
        Uz[9] = static_cast<comp_t>(Gz[3] * zij + Gz[6]);
        Uz[10] = static_cast<comp_t>(Gz[4] * zij + Gz[7]);
        Uz[11] = static_cast<comp_t>(Gz[5] * zij + Gz[8]);
        tile[0] += sc * static_cast<double>(Ux[0] * Uy[0]) * static_cast<double>(Uz[0]);
        tile[1] += sc * static_cast<double>(Ux[1] * Uy[1]) * static_cast<double>(Uz[0]);
        tile[2] += sc * static_cast<double>(Ux[1] * Uy[0]) * static_cast<double>(Uz[1]);
        tile[3] += sc * static_cast<double>(Ux[2] * Uy[2]) * static_cast<double>(Uz[0]);
        tile[4] += sc * static_cast<double>(Ux[2] * Uy[1]) * static_cast<double>(Uz[1]);
        tile[5] += sc * static_cast<double>(Ux[2] * Uy[0]) * static_cast<double>(Uz[2]);
        tile[6] += sc * static_cast<double>(Ux[3] * Uy[3]) * static_cast<double>(Uz[0]);
        tile[7] += sc * static_cast<double>(Ux[4] * Uy[4]) * static_cast<double>(Uz[0]);
        tile[8] += sc * static_cast<double>(Ux[4] * Uy[3]) * static_cast<double>(Uz[1]);
        tile[9] += sc * static_cast<double>(Ux[5] * Uy[5]) * static_cast<double>(Uz[0]);
        tile[10] += sc * static_cast<double>(Ux[5] * Uy[4]) * static_cast<double>(Uz[1]);
        tile[11] += sc * static_cast<double>(Ux[5] * Uy[3]) * static_cast<double>(Uz[2]);
        tile[12] += sc * static_cast<double>(Ux[3] * Uy[0]) * static_cast<double>(Uz[3]);
        tile[13] += sc * static_cast<double>(Ux[4] * Uy[1]) * static_cast<double>(Uz[3]);
        tile[14] += sc * static_cast<double>(Ux[4] * Uy[0]) * static_cast<double>(Uz[4]);
        tile[15] += sc * static_cast<double>(Ux[5] * Uy[2]) * static_cast<double>(Uz[3]);
        tile[16] += sc * static_cast<double>(Ux[5] * Uy[1]) * static_cast<double>(Uz[4]);
        tile[17] += sc * static_cast<double>(Ux[5] * Uy[0]) * static_cast<double>(Uz[5]);
        tile[18] += sc * static_cast<double>(Ux[6] * Uy[6]) * static_cast<double>(Uz[0]);
        tile[19] += sc * static_cast<double>(Ux[7] * Uy[7]) * static_cast<double>(Uz[0]);
        tile[20] += sc * static_cast<double>(Ux[7] * Uy[6]) * static_cast<double>(Uz[1]);
        tile[21] += sc * static_cast<double>(Ux[8] * Uy[8]) * static_cast<double>(Uz[0]);
        tile[22] += sc * static_cast<double>(Ux[8] * Uy[7]) * static_cast<double>(Uz[1]);
        tile[23] += sc * static_cast<double>(Ux[8] * Uy[6]) * static_cast<double>(Uz[2]);
        tile[24] += sc * static_cast<double>(Ux[9] * Uy[9]) * static_cast<double>(Uz[0]);
        tile[25] += sc * static_cast<double>(Ux[10] * Uy[10]) * static_cast<double>(Uz[0]);
        tile[26] += sc * static_cast<double>(Ux[10] * Uy[9]) * static_cast<double>(Uz[1]);
        tile[27] += sc * static_cast<double>(Ux[11] * Uy[11]) * static_cast<double>(Uz[0]);
        tile[28] += sc * static_cast<double>(Ux[11] * Uy[10]) * static_cast<double>(Uz[1]);
        tile[29] += sc * static_cast<double>(Ux[11] * Uy[9]) * static_cast<double>(Uz[2]);
        tile[30] += sc * static_cast<double>(Ux[9] * Uy[6]) * static_cast<double>(Uz[3]);
        tile[31] += sc * static_cast<double>(Ux[10] * Uy[7]) * static_cast<double>(Uz[3]);
        tile[32] += sc * static_cast<double>(Ux[10] * Uy[6]) * static_cast<double>(Uz[4]);
        tile[33] += sc * static_cast<double>(Ux[11] * Uy[8]) * static_cast<double>(Uz[3]);
        tile[34] += sc * static_cast<double>(Ux[11] * Uy[7]) * static_cast<double>(Uz[4]);
        tile[35] += sc * static_cast<double>(Ux[11] * Uy[6]) * static_cast<double>(Uz[5]);
        tile[36] += sc * static_cast<double>(Ux[6] * Uy[0]) * static_cast<double>(Uz[6]);
        tile[37] += sc * static_cast<double>(Ux[7] * Uy[1]) * static_cast<double>(Uz[6]);
        tile[38] += sc * static_cast<double>(Ux[7] * Uy[0]) * static_cast<double>(Uz[7]);
        tile[39] += sc * static_cast<double>(Ux[8] * Uy[2]) * static_cast<double>(Uz[6]);
        tile[40] += sc * static_cast<double>(Ux[8] * Uy[1]) * static_cast<double>(Uz[7]);
        tile[41] += sc * static_cast<double>(Ux[8] * Uy[0]) * static_cast<double>(Uz[8]);
        tile[42] += sc * static_cast<double>(Ux[9] * Uy[3]) * static_cast<double>(Uz[6]);
        tile[43] += sc * static_cast<double>(Ux[10] * Uy[4]) * static_cast<double>(Uz[6]);
        tile[44] += sc * static_cast<double>(Ux[10] * Uy[3]) * static_cast<double>(Uz[7]);
        tile[45] += sc * static_cast<double>(Ux[11] * Uy[5]) * static_cast<double>(Uz[6]);
        tile[46] += sc * static_cast<double>(Ux[11] * Uy[4]) * static_cast<double>(Uz[7]);
        tile[47] += sc * static_cast<double>(Ux[11] * Uy[3]) * static_cast<double>(Uz[8]);
        tile[48] += sc * static_cast<double>(Ux[9] * Uy[0]) * static_cast<double>(Uz[9]);
        tile[49] += sc * static_cast<double>(Ux[10] * Uy[1]) * static_cast<double>(Uz[9]);
        tile[50] += sc * static_cast<double>(Ux[10] * Uy[0]) * static_cast<double>(Uz[10]);
        tile[51] += sc * static_cast<double>(Ux[11] * Uy[2]) * static_cast<double>(Uz[9]);
        tile[52] += sc * static_cast<double>(Ux[11] * Uy[1]) * static_cast<double>(Uz[10]);
        tile[53] += sc * static_cast<double>(Ux[11] * Uy[0]) * static_cast<double>(Uz[11]);
      }
    }
  }

  // Write output tile: FP32 or FP64 depending on kTileF32.
  if constexpr (kTileF32) {
    float* out = eri_out_f32 + static_cast<int64_t>(t) * static_cast<int64_t>(54);
    out[0] = __double2float_rn(tile[0]);
    out[1] = __double2float_rn(tile[1]);
    out[2] = __double2float_rn(tile[2]);
    out[3] = __double2float_rn(tile[3]);
    out[4] = __double2float_rn(tile[4]);
    out[5] = __double2float_rn(tile[5]);
    out[6] = __double2float_rn(tile[6]);
    out[7] = __double2float_rn(tile[7]);
    out[8] = __double2float_rn(tile[8]);
    out[9] = __double2float_rn(tile[9]);
    out[10] = __double2float_rn(tile[10]);
    out[11] = __double2float_rn(tile[11]);
    out[12] = __double2float_rn(tile[12]);
    out[13] = __double2float_rn(tile[13]);
    out[14] = __double2float_rn(tile[14]);
    out[15] = __double2float_rn(tile[15]);
    out[16] = __double2float_rn(tile[16]);
    out[17] = __double2float_rn(tile[17]);
    out[18] = __double2float_rn(tile[18]);
    out[19] = __double2float_rn(tile[19]);
    out[20] = __double2float_rn(tile[20]);
    out[21] = __double2float_rn(tile[21]);
    out[22] = __double2float_rn(tile[22]);
    out[23] = __double2float_rn(tile[23]);
    out[24] = __double2float_rn(tile[24]);
