extern "C" cudaError_t cueri_fused_fock_dsdd_launch_stream(
    const int32_t* task_spAB,
    const int32_t* task_spCD,
    int ntasks,
    const int32_t* sp_A,
    const int32_t* sp_B,
    const int32_t* sp_pair_start,
    const int32_t* sp_npair,
    const double* shell_cx,
    const double* shell_cy,
    const double* shell_cz,
    const double* pair_eta,
    const double* pair_Px,
    const double* pair_Py,
    const double* pair_Pz,
    const double* pair_cK,
    const int32_t* shell_ao_start,
    int nao,
    const double* D_mat,
    double* F_mat,
    cudaStream_t stream,
    int threads,
    int n_bufs,
    bool mixed_prec) {
  if (ntasks < 0 || nao <= 0) return cudaErrorInvalidValue;
  if (ntasks == 0) return cudaSuccess;
  constexpr int kDefaultThreads = 128;
  int launch_threads = 0;
  int blocks = 0;
  constexpr int kGSize_dsdd = 7 * 7;
  constexpr int kWarpDoubles_dsdd = 3 * kGSize_dsdd + 2 * 4 + 11 + 216;
  size_t shmem_dsdd = 0;
  if (mixed_prec) {
    const cudaError_t prep_dsdd = cueri_prepare_fused_fock_warp_launch(
        KernelFusedFock_dsdd_fixed<4, true>,
        threads, kDefaultThreads, ntasks,
        kWarpDoubles_dsdd, &launch_threads, &blocks, &shmem_dsdd);
    if (prep_dsdd != cudaSuccess) return prep_dsdd;
    KernelFusedFock_dsdd_fixed<4, true><<<blocks, launch_threads, shmem_dsdd, stream>>>(
        task_spAB, task_spCD, ntasks, sp_A, sp_B, sp_pair_start, sp_npair,
        shell_cx, shell_cy, shell_cz,
        pair_eta, pair_Px, pair_Py, pair_Pz, pair_cK,
        shell_ao_start, nao, D_mat, F_mat, n_bufs);
  } else {
    const cudaError_t prep_dsdd = cueri_prepare_fused_fock_warp_launch(
        KernelFusedFock_dsdd_fixed<4, false>,
        threads, kDefaultThreads, ntasks,
        kWarpDoubles_dsdd, &launch_threads, &blocks, &shmem_dsdd);
    if (prep_dsdd != cudaSuccess) return prep_dsdd;
    KernelFusedFock_dsdd_fixed<4, false><<<blocks, launch_threads, shmem_dsdd, stream>>>(
        task_spAB, task_spCD, ntasks, sp_A, sp_B, sp_pair_start, sp_npair,
        shell_cx, shell_cy, shell_cz,
        pair_eta, pair_Px, pair_Py, pair_Pz, pair_cK,
        shell_ao_start, nao, D_mat, F_mat, n_bufs);
  }
  return cudaGetLastError();
}

